import{_ as p,C as t,o as y,c as h,j as i,a as m,E as e,a3 as o}from"./chunks/framework.CVjg771q.js";const f=JSON.parse('{"title":"庄子·逍遥游","description":"围绕逍遥游、大鹏小知之辨展开庄子的自由视野。","frontmatter":{"title":"庄子·逍遥游","description":"围绕逍遥游、大鹏小知之辨展开庄子的自由视野。","category":"guide","aliases":["逍遥游","庄子逍遥游","zhuangzi chapter 01"],"source":["《庄子》"]},"headers":[],"relativePath":"daoism/zhuang-zi/chapter-01.md","filePath":"daoism/zhuang-zi/chapter-01.md","lastUpdated":1780591578000}'),s={name:"daoism/zhuang-zi/chapter-01.md"};function l(d,n,u,c,b,x){const g=t("DaoReadingPrelude"),a=t("DaoOriginalReading"),r=t("DaoKeywordCards");return y(),h("div",null,[n[0]||(n[0]=i("h1",{id:"庄子·逍遥游",tabindex:"-1"},[m("庄子·逍遥游 "),i("a",{class:"header-anchor",href:"#庄子·逍遥游","aria-label":'Permalink to "庄子·逍遥游"'},"​")],-1)),e(g,{title:"从大鹏与小知，进入庄子的自由世界",summary:"逍遥游是《庄子》内篇第一篇，也是最常被引用的篇章之一。这一轮先把原文顺下来，看清楚大鹏、蜩鸠、宋荣子、列子、许由、接舆、惠子等人物的出场顺序，以及庄子如何用一个接一个的故事来推「大小之辨」和「无用之用」。",points:[{label:"先看",text:"顺着原文走，看清大鹏→蜩鸠→宋荣子→列子→许由→接舆→惠子的人物链条。"},{label:"再问",text:"庄子为什么从「大小之辨」一直推到「无用之大用」？"},{label:"最后",text:"想一想：今天读到「逍遥」两个字，感受到的是逃避，还是一种更大的自由？"}],hint:"如果你是第一次读庄子，这一篇最需要的是顺着故事走一遍，不需要急着总结。"}),n[1]||(n[1]=i("h2",{id:"一、鲲鹏与小大之辩",tabindex:"-1"},[m("一、鲲鹏与小大之辩 "),i("a",{class:"header-anchor",href:"#一、鲲鹏与小大之辩","aria-label":'Permalink to "一、鲲鹏与小大之辩"'},"​")],-1)),e(a,{paragraphs:["北冥有鱼，其名为鲲。","鲲之大，不知其几千里也；","化而为鸟，其名为鹏。","鹏之背，不知其几千里也；","怒而飞，其翼若垂天之云。","是鸟也，海运则将徙于南冥。","南冥者，天池也。","齐谐者，志怪者也。","谐之言曰：","鹏之徙于南冥也，水击三千里，","抟扶摇而上者九万里，","去以六月息者也。","野马也，尘埃也，","生物之以息相吹也。","天之苍苍，其正色邪？","其远而无所至极邪？","其视下也，亦若是则已矣。","且夫水之积也不厚，","则其负大舟也无力。","覆杯水于坳堂之上，","则芥为之舟；","置杯焉则胶，水浅而舟大也。","风之积也不厚，","则其负大翼也无力，","故九万里则风斯在下矣。","而后乃今培风，","背负青天而莫之夭阏者，","而后乃今将图南。","蜩与学鸠笑之曰：","我决起而飞，抢榆枋，","时则不至，而控于地而已矣；","奚以之九万里而南为？","适莽苍者，三飡而反，腹犹果然；","适百里者，宿舂粮；","适千里者，三月聚粮。","之二虫又何知？","小知不及大知，小年不及大年。","奚以知其然也？","朝菌不知晦朔，","蟪蛄不知春秋，此小年也。","楚之南有冥灵者，","以五百岁为春，五百岁为秋；","上古有大椿者，","以八千岁为春，八千岁为秋。","而彭祖乃今以久特闻，","众人匹之，不亦悲乎？","汤之问棘也是已：","穷发之北有冥海者，天池也。","有鱼焉，其广数千里，","未有知其修者，其名曰鲲。","有鸟焉，其名为鹏，","背若太山，翼若垂天之云；","抟扶摇、羊角而上者九万里","绝云气，负青天，","然后图南，且适南冥也。","斥鴳笑之曰：彼且奚适也？","我腾跃而上，不过数仞而下，","翱翔蓬蒿之间，此亦飞之至也。","而彼且奚适也？此小大之辩也。","故夫知效一官、","行比一乡、德合一君、而徵一国者，","其自视也亦若此矣。","而宋荣子犹然笑之。","且举世而誉之而不加劝，","举世而非之而不加沮，","定乎内外之分，","辩乎荣辱之境，斯已矣。","彼其于世，未数数然也。","虽然，犹有未树也。","夫列子御风而行，泠然善也，","旬有五日而后反。","彼于致福者，未数数然也。","此虽免乎行，犹有所待者也。","若夫乘天地之正，而御六气之辩，","以游无穷者，彼且恶乎待哉？","故曰：","至人无己，神人无功，圣人无名。"]}),e(r,{items:[{term:"冥",pinyin:["míng"],meaning:"亦作溟，海之意。「北冥」就是北方的大海。下文的「南冥」仿此。传说北海无边无际，水深而黑。"},{term:"鲲",pinyin:["kūn"],meaning:"本指鱼卵，这里借表大鱼之名。"},{term:"鹏",pinyin:["péng"],meaning:"本为古「凤」字，这里用表大鸟之名。"},{term:"怒",pinyin:["nù"],meaning:"奋起。"},{term:"垂",pinyin:["chuí"],meaning:"边远；这个意义后代写作「陲」。一说遮，遮天。"},{term:"海运",pinyin:["hǎi","yùn"],meaning:"海水运动，这里指汹涌的海涛；一说指鹏鸟在海面飞行。徙：迁移。"},{term:"天池",pinyin:["tiān","chí"],meaning:"天然的大池。"},{term:"齐谐",pinyin:["qí","xié"],meaning:"书名。一说人名。"},{term:"志",pinyin:["zhì"],meaning:"记载。"},{term:"击",pinyin:["jī"],meaning:"拍打，这里指鹏鸟奋飞而起双翼拍打水面。"},{term:"抟",pinyin:["tuán"],meaning:"环绕而上。一说「抟」当作「搏」(bó)，拍击的意思。扶摇：又名叫飙，由地面急剧盘旋而上的暴风。"},{term:"去",pinyin:["qù"],meaning:"离，这里指离开北海。息：停歇。"},{term:"野马",pinyin:["yě","mǎ"],meaning:"春天林泽中的雾气。雾气浮动状如奔马，故名「野马」。"},{term:"尘埃",pinyin:["chén","āi"],meaning:"扬在空中的土叫「尘」，细碎的尘粒叫「埃」。"},{term:"生物",pinyin:["shēng","wù"],meaning:"概指各种有生命的东西。息：这里指有生命的东西呼吸所产生的气息。"},{term:"极",pinyin:["jí"],meaning:"尽。"},{term:"覆",pinyin:["fù"],meaning:"倾倒。坳(ào)：坑凹处，「坳堂」指厅堂地面上的坑凹处。"},{term:"芥",pinyin:["jiè"],meaning:"小草。"},{term:"斯",pinyin:["sī"],meaning:"则，就。"},{term:"而后乃今",pinyin:["ér","hòu","nǎi","jīn"],meaning:"意思是这之后方才；以下同此解。培：通作「凭」，凭借。"},{term:"莫",pinyin:["mò"],meaning:"这里作没有什么力量讲。夭阏(è)：又写作「夭遏」，意思是遏阻、阻拦。「莫之夭阏」即「莫夭阏之」的倒装。"},{term:"蜩",pinyin:["tiáo"],meaning:"蝉。学鸠：一种小灰雀，这里泛指小鸟。"},{term:"决",pinyin:["xuè"],meaning:"通作「翅」，迅疾的样子。"},{term:"抢",pinyin:["qiāng"],meaning:"突过。榆枋：两种树名。"},{term:"控",pinyin:["kòng"],meaning:"投下，落下来。"},{term:"奚以",pinyin:["xī","yǐ"],meaning:"何以。之：去到。为：句末疑问语气词。"},{term:"适",pinyin:["shì"],meaning:"往，去到。莽苍：指迷茫看不真切的郊野。"},{term:"飡",pinyin:["cān"],meaning:"同餐。反：返回。"},{term:"犹",pinyin:["yóu"],meaning:"还。果然：饱的样子。"},{term:"宿",pinyin:["sù"],meaning:"这里指一夜。"},{term:"二虫",pinyin:["èr","chóng"],meaning:"指上述的蜩与学鸠。"},{term:"知",pinyin:["zhì"],meaning:"通「智」，智慧。"},{term:"朝菌",pinyin:["zhāo","jùn"],meaning:"清晨生、见日则死的菌类。晦朔：一个月的最后一天和最初天。一说「晦」指黑夜，「朔」指清晨。"},{term:"蟪蛄",pinyin:["huì","gū"],meaning:"即寒蝉，春生夏死或夏生秋死。"},{term:"冥灵",pinyin:["míng","líng"],meaning:"传说中的大龟，一说树名。"},{term:"大椿",pinyin:["dà","chūn"],meaning:"传说中的古树名。"},{term:"彭祖",pinyin:["péng","zǔ"],meaning:"古代传说中年寿最长的人。乃今：而今。以：凭。特：独。闻：闻名于世。"},{term:"匹",pinyin:["pǐ"],meaning:"配，比。"},{term:"汤",pinyin:["tāng"],meaning:"商汤。棘：汤时的贤大夫。已：矣。"},{term:"穷发",pinyin:["qióng","fà"],meaning:"不长草木的地方。"},{term:"修",pinyin:["xiū"],meaning:"长。"},{term:"太山",pinyin:["tài","shān"],meaning:"大山。一说即泰山。"},{term:"羊角",pinyin:["yáng","jiǎo"],meaning:"旋风，回旋向上如羊角状。"},{term:"绝",pinyin:["jué"],meaning:"穿过。"},{term:"斥鴳",pinyin:["chì","yàn"],meaning:"一种小鸟。"},{term:"仞",pinyin:["rèn"],meaning:"古代长度单位，周制为八尺，汉制为七尺；这里应从周制。"},{term:"至",pinyin:["zhì"],meaning:"极点。"},{term:"辩",pinyin:["biàn"],meaning:"通作「辨」，辨别、区分的意思。"},{term:"效",pinyin:["xiào"],meaning:"功效；这里含有胜任的意思。官：官职。"},{term:"行",pinyin:["xíng"],meaning:"品行。比：比并。"},{term:"而",pinyin:["néng"],meaning:"通作「能」，能力。徵：取信。"},{term:"宋荣子",pinyin:["sòng","róng","zǐ"],meaning:"一名宋钘，宋国人，战国时期的思想家。犹然：讥笑的样子。"},{term:"举",pinyin:["jǔ"],meaning:"全。劝：劝勉，努力。"},{term:"非",pinyin:["fēi"],meaning:"责难，批评。沮(jǔ)：沮丧。"},{term:"内外",pinyin:["nèi","wài"],meaning:"这里分别指自身和身外之物。庄子认为，自主的精神是内在的，荣誉和非难都是外在的，而只有自主的精神才是重要的、可贵的。"},{term:"境",pinyin:["jìng"],meaning:"界限。"},{term:"数数然",pinyin:["shuò","shuò","rán"],meaning:"急急忙忙的样子。"},{term:"列子",pinyin:["liè","zǐ"],meaning:"郑国人，名叫列御寇，战国时代思想家。御：驾驭。"},{term:"泠然",pinyin:["líng","rán"],meaning:"轻盈美好的样子。"},{term:"旬",pinyin:["xún"],meaning:"十天。有：又。"},{term:"致",pinyin:["zhì"],meaning:"罗致，这里有寻求的意思。"},{term:"待",pinyin:["dài"],meaning:"凭借，依靠。"},{term:"乘",pinyin:["chéng"],meaning:"遵循，凭借。天地：这里指万物，指整个自然界。正：本；这里指自然的本性。"},{term:"御",pinyin:["yù"],meaning:"含有因循、顺着的意思。六气：指阴、阳、风、雨、晦、明。辩：通作「变」，变化的意思。"},{term:"恶",pinyin:["wū"],meaning:"何，什么。"},{term:"至人",pinyin:["zhì","rén"],meaning:"这里指道德修养最高尚的人。无己：清除外物与自我的界限，达到忘掉自己的境界。"},{term:"神人",pinyin:["shén","rén"],meaning:"这里指精神世界完全能超脱于物外的人。无功：不建树功业。"},{term:"圣人",pinyin:["shèng","rén"],meaning:"这里指思想修养臻于完美的人。无名：不追求名誉地位。"}]}),n[2]||(n[2]=i("h2",{id:"二、尧让天下-·-藐姑射之神人",tabindex:"-1"},[m("二、尧让天下 · 藐姑射之神人 "),i("a",{class:"header-anchor",href:"#二、尧让天下-·-藐姑射之神人","aria-label":'Permalink to "二、尧让天下 · 藐姑射之神人"'},"​")],-1)),e(a,{paragraphs:["尧让天下于许由，曰：","日月出矣，而爝火不息；","其于光也，不亦难乎？","时雨降矣，而犹浸灌；","其于泽也，不亦劳乎？","夫子立而天下治，而我犹尸之；","吾自视缺然，请致天下。","许由曰：","子治天下，天下既已治也；","而我犹代子，吾将为名乎？","名者，实之宾也；","吾将为宾乎？","鹪鹩巢于深林，不过一枝；","偃鼠饮河，不过满腹。","归休乎君，予无所用天下为","庖人虽不治庖，","尸祝不越樽俎而代之矣","肩吾问于连叔曰","吾闻言于接舆，","大而无当，往而不反。","吾惊怖其言。","犹河汉而无极也","大有迳庭，不近人情焉。","连叔曰：其言谓何哉？曰","藐姑射之山，有神人居焉。","肌肤若冰雪，淖约若处子，","不食五谷，吸风饮露，","乘云气，御飞龙，而游乎四海之外","其神凝，使物不疵疠而年谷熟。","吾以是狂而不信也。","连叔曰：然。","瞽者无以与乎文章之观，","聋者无以与乎钟鼓之声。","岂唯形骸有聋盲哉？","夫知亦有之！","是其言也犹时女也。","之人也，之德也，","将旁礴万物以为一，","世蕲乎乱，孰弊弊焉以天下为事","之人也，物莫之伤","大浸稽天而不溺，","大旱金石流，土山焦而不热。","是其尘垢秕穅将犹陶铸尧舜者也，","孰肯以物为事？","宋人资章甫而适诸越，","越人断发文身，无所用之。","尧治天下之民，平海内之政，","往见四子藐姑射之山，","汾水之阳，","窅然丧其天下焉。"]}),e(r,{items:[{term:"尧",pinyin:["yáo"],meaning:"我国历史上传说时代的圣明君主。许由：古代传说中的高士，宇仲武，隐于箕山。相传尧要让天下给他，他自命高洁而不受。"},{term:"爝火",pinyin:["jué","huǒ"],meaning:"炬火，木材上蘸上油脂燃起的火把。"},{term:"时雨",pinyin:["shí","yǔ"],meaning:"按时令季节及时降下的雨。"},{term:"浸灌",pinyin:["jìn","guàn"],meaning:"灌溉。"},{term:"泽",pinyin:["zé"],meaning:"润泽。"},{term:"劳",pinyin:["láo"],meaning:"这里含有徒劳的意思。"},{term:"立",pinyin:["lì"],meaning:"位，在位。"},{term:"尸",pinyin:["shī"],meaning:"庙中的神主，这里用其空居其位，虚有其名之义。"},{term:"缺然",pinyin:["quē","rán"],meaning:"不足的样子。"},{term:"致",pinyin:["zhì"],meaning:"给与。"},{term:"子",pinyin:["zǐ"],meaning:"对人的尊称。"},{term:"宾",pinyin:["bīn"],meaning:"次要的、派生的东西。"},{term:"鹪鹩",pinyin:["jiāo","liáo"],meaning:"一种善于筑巢的小鸟。"},{term:"偃鼠",pinyin:["yǎn","shǔ"],meaning:"鼹鼠。"},{term:"休",pinyin:["xiū"],meaning:"止，这里是算了的意思。"},{term:"为",pinyin:["wéi"],meaning:"句末疑问语气词。"},{term:"庖人",pinyin:["páo","rén"],meaning:"厨师。"},{term:"尸祝",pinyin:["shī","zhù"],meaning:"祭祀时主持祭祀的人。樽：酒器。俎：盛肉的器皿。成语「越俎代庖」出于此。"},{term:"肩吾",pinyin:["jiān","wú"],meaning:"与连叔皆为庄子为表达需要而虚构的人物。"},{term:"接舆",pinyin:["jiē","yú"],meaning:"楚国的隐士，姓陆名通，接舆为字。"},{term:"当",pinyin:["dàng"],meaning:"底，边际。"},{term:"反",pinyin:["fǎn"],meaning:"返。"},{term:"河汉",pinyin:["hé","hàn"],meaning:"银河。极：边际，尽头。"},{term:"迳庭",pinyin:["jìng","tíng"],meaning:"迳指门外小路，庭指堂外之地。连用喻指差异很大。成语「大相迳庭」出于此。"},{term:"藐",pinyin:["miǎo"],meaning:"遥远的样子。姑射(yè)：传说中的山名。"},{term:"淖约",pinyin:["chuò","yuē"],meaning:"柔弱、美好的样子。处子：处女。"},{term:"凝",pinyin:["níng"],meaning:"指神情专一。"},{term:"疵疠",pinyin:["cī","lì"],meaning:"疾病。"},{term:"以",pinyin:["yǐ"],meaning:"认为。狂：通作「诳」，虚妄之言。信：真实可靠。"},{term:"瞽",pinyin:["gǔ"],meaning:"盲。文章：花纹、色彩。"},{term:"时",pinyin:["shí"],meaning:"是。女：汝，你。旧注指时女为处女，联系上下文实是牵强，故未从。"},{term:"旁礴",pinyin:["páng","bó"],meaning:"混同的样子。"},{term:"蕲",pinyin:["qí"],meaning:"祈；求的意思。乱：这里作「治」讲，这是古代同词义反的语言现象。"},{term:"弊弊焉",pinyin:["bì","bì","yān"],meaning:"忙忙碌碌、疲惫不堪的样子。"},{term:"大浸",pinyin:["dà","jìn"],meaning:"大水。稽：至。"},{term:"秕穅",pinyin:["bǐ","kāng"],meaning:"瘪谷和糠。陶：用土烧制瓦器。铸：熔炼金属铸造器物。"},{term:"资",pinyin:["zī"],meaning:"贩卖。章甫：古代殷地人的一种礼帽。适：往。"},{term:"断发文身",pinyin:["duàn","fà","wén","shēn"],meaning:"不蓄头发，在身上刺满花纹。越国处南方，习俗与中原的宋国不同。"},{term:"四子",pinyin:["sì","zǐ"],meaning:"旧注指王倪、齧缺、被衣、许由四人，实为虚构的人物。阳：山的南面或水流的北面。"},{term:"窅然",pinyin:["yǎo","rán"],meaning:"怅然若失的样子。丧(shàng)：丧失、忘掉。"}]}),n[3]||(n[3]=i("h2",{id:"三、惠子大瓠之辩",tabindex:"-1"},[m("三、惠子大瓠之辩 "),i("a",{class:"header-anchor",href:"#三、惠子大瓠之辩","aria-label":'Permalink to "三、惠子大瓠之辩"'},"​")],-1)),e(a,{paragraphs:["惠子谓庄子曰：","魏王贻我大瓠之种，","我树之成，而实五石。","以盛水浆，其坚不能自举也。","剖之以为瓢，则瓠落无所容。","非不呺然大也，","吾为其无用而掊之。","庄子曰：","夫子固拙于用大矣！","宋人有善为不龟手之药者，","世世以洴澼絖为事。","客闻之，请买其方百金。","聚族而谋曰","我世世为洴澼絖，不过数金；","今一朝而鬻技百金，请与之。","客得之，以说吴王。","越有难，吴王使之将，","冬与越人水战，","大败越人，裂地而封之。","能不龟手一也，或以封，","或不免于洴澼絖，","则所用之异也。","今子有五石之瓠，","何不虑以为大樽，","而浮于江湖，","而忧其瓠落无所容？","则夫子犹有蓬之心也夫！"]}),e(r,{items:[{term:"惠子",pinyin:["huì","zǐ"],meaning:"宋国人，姓惠名施，做过梁惠王的相。本篇及后面多为寓言性质，并不真正反映惠施的思想。"},{term:"魏王",pinyin:["wèi","wáng"],meaning:"即梁惠王。贻(yí)：赠送。瓠(hú)：葫芦。"},{term:"树",pinyin:["shù"],meaning:"种植、培育。"},{term:"实",pinyin:["shí"],meaning:"结的葫芦。石(dàn)：容量单位，十斗为一石。"},{term:"举",pinyin:["jǔ"],meaning:"拿起来。"},{term:"瓠落",pinyin:["hù","luò"],meaning:"又写作「廓落」，很大很大的样子。"},{term:"呺然",pinyin:["xiāo","rán"],meaning:"庞大而又中空的样子。"},{term:"掊",pinyin:["pǒu"],meaning:"砸破。为(wèi)：因为。"},{term:"固",pinyin:["gù"],meaning:"实在，确实。"},{term:"龟",pinyin:["jūn"],meaning:"通作「皲」，皮肤受冻开裂。"},{term:"洴澼絖",pinyin:["píng","pì","kuàng"],meaning:"洴(píng)：浮。澼(pí)：在水中漂洗。絖(kuàng)：丝絮。"},{term:"方",pinyin:["fāng"],meaning:"药方。"},{term:"鬻",pinyin:["yù"],meaning:"卖，出售。"},{term:"说",pinyin:["shuì"],meaning:"劝说，游说。"},{term:"难",pinyin:["nàn"],meaning:"发难，这里指越国对吴国有军事行动。"},{term:"将",pinyin:["jiàng"],meaning:"统帅部队。"},{term:"裂",pinyin:["liè"],meaning:"划分出。"},{term:"一",pinyin:["yī"],meaning:"同一，一样的。或：无定代词，这里指有的人。以：凭借。"},{term:"虑",pinyin:["lǜ"],meaning:"考虑。一说通作「摅」，用绳络缀结。樽：本为酒器，这里指形似酒樽的腰舟。"},{term:"蓬之心",pinyin:["péng","zhī","xīn"],meaning:"蓬为草名，其状弯曲不直。「有蓬之心」喻指见识浅薄不能通晓大道理。"}]}),n[4]||(n[4]=i("h2",{id:"四、惠子大树樗之辩",tabindex:"-1"},[m("四、惠子大树樗之辩 "),i("a",{class:"header-anchor",href:"#四、惠子大树樗之辩","aria-label":'Permalink to "四、惠子大树樗之辩"'},"​")],-1)),e(a,{paragraphs:["惠子谓庄子曰","吾有大树，人谓之樗。","其大本拥肿而不中绳墨，","其小枝卷曲而不中规矩，","立之塗，匠人不顾。","今子之言大而无用，","众所同去也。","庄子曰：子独不见狸狌乎？","卑身而伏，以候敖者；","东西跳梁，不辟高下；","中于机辟，死于罔罟。","今夫斄牛，其大若垂天之云。","此能为大矣，而不能执鼠。","今子有大树，患其无用，","何不树之于无何有之乡，","广莫之野，彷徨乎无为其侧，","逍遥乎寝卧其下。","不夭斤斧，物无害者，","无所可用，安所困苦哉！"]}),e(r,{items:[{term:"樗",pinyin:["chū"],meaning:"一种高大的落叶乔木，但木质粗劣不可用。"},{term:"大本",pinyin:["dà","běn"],meaning:"树干粗大。拥肿：今写作「臃肿」，这里形容树干弯曲、疙里疙瘩。中(zhòng)：符合。绳墨：木工用以求直的墨线。"},{term:"规矩",pinyin:["guī","jǔ"],meaning:"即圆规和角尺。"},{term:"塗",pinyin:["tú"],meaning:"通作「途」，道路。"},{term:"狸狌",pinyin:["lí","shēng"],meaning:"狸(lí)：野猫。狌(shēng)：黄鼠狼。"},{term:"卑",pinyin:["bēi"],meaning:"低。"},{term:"敖",pinyin:["áo"],meaning:"通「遨」，遨游。"},{term:"跳梁",pinyin:["tiào","liáng"],meaning:"跳踉，跳跃、窜越的意思。"},{term:"辟",pinyin:["bì"],meaning:"避开；这个意义后代写作「避」。"},{term:"机辟",pinyin:["jī","pì"],meaning:"捕兽的机关陷阱。"},{term:"罔罟",pinyin:["wǎng","gǔ"],meaning:"罔：网。罟：网的总称。"},{term:"斄牛",pinyin:["lí","niú"],meaning:"牦牛。"},{term:"无何有之乡",pinyin:["wú","hé","yǒu","zhī","xiāng"],meaning:"指什么也没有生长的地方。"},{term:"莫",pinyin:["mò"],meaning:"大。"},{term:"彷徨",pinyin:["páng","huáng"],meaning:"徘徊，纵放。无为：无所事事。"},{term:"夭",pinyin:["yāo"],meaning:"夭折。斤：伐木之斧。"}]}),n[5]||(n[5]=o('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>逍遥游以「大小之辨」为线索，通过大鹏图南、蜩鸠笑之、朝菌蟪蛄、宋荣子列子、许由尧让、姑射神人、大瓠之辩、无用大树等层层递进的故事群，展示一条从「被小知小用束缚」到「在无用中得大用」的自由之路。表面的「逍遥」是自在飞翔，深层的「逍遥」是与天地精神相往来。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>逍遥游是庄子内篇的开门篇，也是全书追问「人如何活得更大、更自由」的总纲。第一，它建立了「大小之辨」的思维框架——不是要否定小，而是要人不被小所限；第二，它提出「无待」的理想——任何依赖（风、水、名、功）都会限制自由；第三，它给出「无用之用」的实践智慧——真正的自由不在急功近利中，而在不被功利眼光衡量时反而有用。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>今天读逍遥游，最直接的进入方式是先放下「总结中心思想」的冲动，顺着故事走一遍。然后问自己三个问题：① 你生活中哪些「小知」（别人的评价、短期成败）在限制你看见更大的可能？② 「无用」在你这里是否总被忽略——那些不直接产生效益的阅读、思考、关系，是否反而是你真正的根基？③ 庄子的「逍遥」不是躺平，你觉得它和「躺平」的区别在哪里？</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《庄子》</li></ul>',13))])}const j=p(s,[["render",l]]);export{f as __pageData,j as default};
